import React, { useState } from 'react';
import './Flipbook.css';

const Flipbook = () => {
  const [currentPage, setCurrentPage] = useState(1);

  const handleFlipbookClick = () => {
    setCurrentPage(currentPage === 1 ? 2 : 1);
  };

  return (
    <div className="flipbook-container" onClick={handleFlipbookClick}>
      <div className={`flipbook-page flipbook-page-1 ${currentPage === 1 ? 'flipbook-page-front' : 'flipbook-page-back'}`} />
      <div className={`flipbook-page flipbook-page-2 ${currentPage === 1 ? 'flipbook-page-back' : 'flipbook-page-front'}`} />
    </div>
  );
};

export default Flipbook;
